SELECT speaker_id, topic
FROM speaker_topics
WHERE speaker_id = 1;

SELECT COUNT(*) AS review_count
FROM reviews
WHERE review_date = '2023-05-01';

SELECT speaker_id, COUNT(*) AS total_publications
FROM speaker_publications
GROUP BY speaker_id;

SELECT AVG(keyword_count) AS average_keywords_per_speaker
FROM (
  SELECT COUNT(speaker_keyword_id) AS keyword_count
  FROM speaker_keywords
  GROUP BY speaker_id
) AS keyword_counts;

SELECT speaker_id, COUNT(review_id) AS review_count
FROM speaker_reviews
GROUP BY speaker_id;

SELECT speaker_name
FROM speakers
ORDER BY speaker_name ASC;

SELECT publication_title
FROM speaker_publications
ORDER BY publication_date ASC;
